	{
		scanf("%d",&a[i]);
	}
	for(int i=1;i<=n;i++)
	{
		d=a[i];
		hw=a[i];
		c=0;
		while(d>0)
		{
			e=d%10;
			c=c*10+e;
			d/=10;
		}
		if(c==a[i])
		{	
			if(c>maxn)
